// Extraer campos de la factura parseada (JSON puro, sin módulos externos)
const results = [];

for (const item of $input.all()) {
  try {
    const data = item.json.data || item.json;

    let nit = 'N/A';
    let razonSocial = 'N/A';
    let numFactura = 'N/A';
    let fecha = 'N/A';
    let total = 0;
    let descripcion = 'N/A';

    // Detectar AttachedDocument o Invoice
    const doc = data.AttachedDocument || data['AttachedDocument'];
    const inv = data.Invoice || data['Invoice'];

    if (doc) {
      // Formato AttachedDocument (factura electrónica colombiana)
      numFactura = doc.ID?.[0] || doc.ID || 'N/A';
      fecha = doc.IssueDate?.[0] || doc.IssueDate || 'N/A';

      // SenderParty
      const sender = doc.SenderParty?.[0] || doc.SenderParty;
      if (sender) {
        const taxScheme = sender.PartyTaxScheme?.[0] || sender.PartyTaxScheme;
        if (taxScheme) {
          const compId = taxScheme.CompanyID?.[0] || taxScheme.CompanyID;
          nit = typeof compId === 'object' ? (compId._ || compId['#text'] || JSON.stringify(compId)) : (compId || 'N/A');
          razonSocial = taxScheme.RegistrationName?.[0] || taxScheme.RegistrationName || 'N/A';
        }
      }

      // Intentar extraer total de la factura embebida
      // La factura embebida está como texto en Attachment.ExternalReference.Description
      // Pero ya parseada por el nodo XML, podría estar como objeto
      const attachment = doc.Attachment?.[0] || doc.Attachment;
      if (attachment) {
        const extRef = attachment.ExternalReference?.[0] || attachment.ExternalReference;
        if (extRef) {
          const descContent = extRef.Description?.[0] || extRef.Description;
          // Si el nodo XML parseó la factura embebida
          if (typeof descContent === 'object' && descContent.Invoice) {
            const embInv = descContent.Invoice;
            const lmt = embInv.LegalMonetaryTotal?.[0] || embInv.LegalMonetaryTotal;
            if (lmt) {
              const payable = lmt.PayableAmount?.[0] || lmt.PayableAmount;
              total = parseFloat(typeof payable === 'object' ? (payable._ || payable['#text'] || 0) : payable) || 0;
            }
            // Descripción
            let line = embInv.InvoiceLine;
            if (Array.isArray(line)) line = line[0];
            if (line) {
              const lineItem = line.Item?.[0] || line.Item;
              if (lineItem) {
                descripcion = lineItem.Description?.[0] || lineItem.Description || lineItem.Name?.[0] || lineItem.Name || 'N/A';
              }
            }
          }
        }
      }
    } else if (inv) {
      // Invoice directo
      numFactura = inv.ID?.[0] || inv.ID || 'N/A';
      fecha = inv.IssueDate?.[0] || inv.IssueDate || 'N/A';

      const supplier = inv.AccountingSupplierParty?.[0]?.Party?.[0] || inv.AccountingSupplierParty?.Party;
      if (supplier) {
        const taxScheme = supplier.PartyTaxScheme?.[0] || supplier.PartyTaxScheme;
        if (taxScheme) {
          const compId = taxScheme.CompanyID?.[0] || taxScheme.CompanyID;
          nit = typeof compId === 'object' ? (compId._ || compId['#text'] || 'N/A') : (compId || 'N/A');
          razonSocial = taxScheme.RegistrationName?.[0] || taxScheme.RegistrationName || 'N/A';
        }
      }

      const lmt = inv.LegalMonetaryTotal?.[0] || inv.LegalMonetaryTotal;
      if (lmt) {
        const payable = lmt.PayableAmount?.[0] || lmt.PayableAmount;
        total = parseFloat(typeof payable === 'object' ? (payable._ || payable['#text'] || 0) : payable) || 0;
      }

      let line = inv.InvoiceLine;
      if (Array.isArray(line)) line = line[0];
      if (line) {
        const lineItem = line.Item?.[0] || line.Item;
        if (lineItem) {
          descripcion = lineItem.Description?.[0] || lineItem.Description || lineItem.Name?.[0] || lineItem.Name || 'N/A';
        }
      }
    }

    results.push({
      json: {
        nit_emisor: String(nit).trim(),
        razon_social: String(razonSocial).trim(),
        numero_factura: String(numFactura).trim(),
        fecha_emision: String(fecha).trim(),
        valor_total: total,
        descripcion: String(descripcion).trim(),
        procesado_en: new Date().toISOString()
      }
    });
  } catch (error) {
    results.push({
      json: {
        nit_emisor: 'N/A',
        razon_social: 'N/A',
        numero_factura: 'N/A',
        fecha_emision: 'N/A',
        valor_total: 0,
        descripcion: 'N/A',
        error: error.message,
        procesado_en: new Date().toISOString()
      }
    });
  }
}

return results;
